#!/bin/zsh
# Deploy KORA AM Dashboard to Fly.io
# Prerequisites: flyctl auth login (one time, opens browser)
export PATH="/Users/jcvs/.fly/bin:$PATH"
SHEET_ID="1QD5lCvnJU5etIUzoslESI36wi5x0jln57YG_3H4QJKU"
SA_B64=""

cd /Users/jcvs/Desktop/kora-am-platform/dashboard

echo "🚀 Deploying KORA AM Dashboard to Fly.io..."

# Create app if it doesn't exist
flyctl apps create kora-am-dashboard --org personal 2>/dev/null || true

# Set secrets
flyctl secrets set \
  PRY002_SHEET_ID="$SHEET_ID" \
  SA_JSON_B64="$SA_B64" \
  --app kora-am-dashboard

# Deploy
flyctl deploy --app kora-am-dashboard

echo "✅ Deploy complete!"
echo "URL: https://kora-am-dashboard.fly.dev"
